const FeatureBetaBilling ffx.Feature = "beta-billing"

// At wiring time:
svc := ffx.NewStaticService(ffx.AccessConfig{FeatureBetaBilling: cfg.BillingEnabled})

// In handler:
enabled, err := svc.IsFeatureEnabled(ctx, FeatureBetaBilling)
if err != nil {
    return fmt.Errorf("feature flag: %w", err)
}
if enabled {
    // use new billing path
}

import (
    "github.com/openmeterio/openmeter/pkg/filter"
    "github.com/samber/lo"
)

f := filter.FilterString{Contains: lo.ToPtr("acme")}
if err := f.Validate(); err != nil {
    return nil, err
}

// Ent path:
if pred := f.Select("display_name"); pred != nil {
    query = query.Where(pred)
}

// ClickHouse / go-sqlbuilder path:
q := sqlbuilder.Select("*").From("events")
if expr := f.SelectWhereExpr("display_name", q); expr != "" {
    q.Where(expr)
}

